import pickle
from datetime import datetime
from os import path
from flask import Flask, request, jsonify
from typing import Any

app = Flask(__name__)

# Cache directory and timeout (in seconds)
CACHE_DIR = 'cache'
TIMEOUT = 60 * 30  # 30 minutes

def cache_key(url: str) -> str:
    return url + '.pkl'

def serialize(data: Any) -> bytes:
    return pickle.dumps(data)

def deserialize(data: bytes) -> Any:
    try:
        return pickle.loads(data)
    except Exception as e:
        raise Exception(f'Failed to load cached data: {e}')

def cache_response(url: str, response: dict):
    file_path = path.join(CACHE_DIR, cache_key(url))
    
    # Check if the file exists and is not older than 30 minutes
    try:
        timestamp = int(path.getmtime(file_path))
        if datetime.now().timestamp() - timestamp < TIMEOUT:
            with open(file_path, 'rb') as f:
                cached_response = deserialize(f.read())
            return jsonify(cached_response)
    except FileNotFoundError:
        pass

    # Cache the response
    data_to_cache = {'response': response}
    with open(file_path, 'wb') as f:
        f.write(serialize(data_to_cache))
    
    return jsonify(response)

@app.route('/api/<url>', methods=['GET'])
def get_response(url: str):
    if url.startswith('http://') or url.startswith('https://'):
        cached_response = cache_response(url, request.get_json())
        return cached_response
    
    return 'Invalid URL'